import { NextRequest, NextResponse } from "next/server"
import { prisma } from "@/lib/prisma"
import { authenticateRequest } from "@/lib/auth"
import { cloudinary } from "@/lib/cloudinary"
import sharp from "sharp"

export async function GET(
  request: NextRequest,
  { params }: { params: { id: string } }
) {
  try {
    const user = await authenticateRequest(request)
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
    }

    const transfer = await prisma.moneyTransfer.findUnique({
      where: { id: params.id },
      include: {
        sender: {
          select: {
            id: true,
            name: true,
            email: true,
            phone: true,
            avatar: true,
          },
        },
        receiver: {
          select: {
            id: true,
            name: true,
            email: true,
            phone: true,
            avatar: true,
          },
        },
      },
    })

    if (!transfer) {
      return NextResponse.json({ error: "Transaction not found" }, { status: 404 })
    }

    if (transfer.senderId !== user.id && transfer.receiverId !== user.id) {
      return NextResponse.json({ error: "Unauthorized access to this transaction" }, { status: 403 })
    }

    if (transfer.receiptImageUrl) {
      return NextResponse.json({
        success: true,
        receiptUrl: transfer.receiptImageUrl,
        publicId: transfer.receiptCloudinaryPublicId ?? undefined,
        cached: true,
      })
    }

    const isSender = transfer.senderId === user.id
    const otherUser = isSender ? transfer.receiver : transfer.sender

    const svgReceipt = generateSVGReceipt(transfer, otherUser, isSender)

    try {
      const { secure_url, public_id } = await uploadReceiptPngToCloudinary(transfer.id, svgReceipt)

      await prisma.moneyTransfer.update({
        where: { id: transfer.id },
        data: {
          receiptImageUrl: secure_url,
          receiptCloudinaryPublicId: public_id,
        },
      })

      return NextResponse.json({
        success: true,
        receiptUrl: secure_url,
        publicId: public_id,
        cached: false,
      })
    } catch (uploadErr: any) {
      console.error("Receipt PNG upload error:", uploadErr)
      return NextResponse.json(
        {
          error: "Receipt generation failed",
          detail: process.env.NODE_ENV === "development" ? uploadErr?.message : undefined,
        },
        { status: 500 }
      )
    }
  } catch (error: any) {
    console.error("Error generating receipt:", error)
    return NextResponse.json(
      { error: error.message || "Failed to generate receipt" },
      { status: 500 }
    )
  }
}

/**
 * Rasterize SVG → PNG locally with sharp (reliable), upload PNG bytes to Cloudinary.
 * Falls back to SVG upload + eager PNG if sharp cannot parse the SVG.
 */
async function uploadReceiptPngToCloudinary(
  transferId: string,
  svg: string
): Promise<{ secure_url: string; public_id: string }> {
  const folder = "money-transfer/receipts"
  const publicIdBase = `mt_${transferId}`

  await cloudinary.uploader.destroy(`${folder}/${publicIdBase}`).catch(() => {})

  const svgBuf = Buffer.from(svg, "utf8")

  let pngBuffer: Buffer | null = null
  try {
    pngBuffer = await sharp(svgBuf, { density: 144 })
      .resize({
        width: 800,
        // height removed to let it auto-scale based on dynamic SVG layout height
        withoutEnlargement: true,
      })
      .png()
      .toBuffer()
  } catch (e) {
    console.warn("[receipt] sharp SVG→PNG failed, trying Cloudinary eager:", e)
  }

  if (pngBuffer) {
    return await new Promise((resolve, reject) => {
      const stream = cloudinary.uploader.upload_stream(
        {
          folder,
          public_id: publicIdBase,
          overwrite: true,
          resource_type: "image",
          format: "png",
        },
        (err, result) => {
          if (err) {
            reject(err)
            return
          }
          if (result?.secure_url && result.public_id) {
            resolve({ secure_url: result.secure_url, public_id: result.public_id })
            return
          }
          reject(new Error("Cloudinary returned no URL for PNG upload"))
        }
      )
      stream.end(pngBuffer)
    })
  }

  // Fallback: load SVG in Cloudinary, request eager PNG transformation
  const b64 = svgBuf.toString("base64")
  const dataUri = `data:image/svg+xml;base64,${b64}`

  const uploadResult: any = await cloudinary.uploader.upload(dataUri, {
    folder,
    public_id: publicIdBase,
    overwrite: true,
    resource_type: "image",
    format: "svg",
    eager: [{ width: 800, crop: "scale", format: "png", fetch_format: "png" }],
    eager_async: false,
  })

  const eagerPng = uploadResult?.eager?.[0]?.secure_url as string | undefined
  if (eagerPng) {
    return { secure_url: eagerPng, public_id: uploadResult.public_id as string }
  }

  if (uploadResult?.secure_url) {
    const pngUrl = cloudinary.url(uploadResult.public_id, {
      secure: true,
      resource_type: "image",
      format: "png",
      transformation: [{ fetch_format: "png", quality: "auto:good" }],
    })
    return { secure_url: pngUrl, public_id: uploadResult.public_id as string }
  }

  throw new Error("Could not produce PNG receipt (sharp + Cloudinary)")
}

function escapeXml(s: string): string {
  return s
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
}

function generateSVGReceipt(transfer: any, otherUser: any, isSender: boolean) {
  // 1. IMPORTANT: UPDATE THIS TO YOUR LOGO
  // Note: For sharp to successfully render the logo, Base64 is heavily recommended 
  // over a remote http:// link, as sharp doesn't fetch external URLs during rasterization.
  const LOGO_HREF = "data:image/png;base64,"; // REPLACE WITH ACTUAL LOGO BASE64

  const dateObj = new Date(transfer.createdAt);
  const formattedDate = dateObj.toLocaleDateString("en-US", {
    day: "numeric", month: "short", year: "numeric",
    hour: "2-digit", minute: "2-digit",
  });

  const isSuccess = transfer.status === "COMPLETED" || transfer.status === "SENT";
  const isFailed = transfer.status === "FAILED";
  
  const statusColor = isSuccess ? "#10b981" : isFailed ? "#ef4444" : "#f59e0b";
  const statusTitle = isSuccess ? "Transfer Successful" : isFailed ? "Transfer Failed" : "Processing";

  const partyName = otherUser?.name || "Unknown";
  const desc = transfer.description || "";

  const formattedAmount = Number(transfer.amount).toLocaleString('en-US', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });

  // 2. Dynamic Layout Calculations
  const startY = 140; 
  const perforationY = 260; 
  const rowHeight = 40;
  const leftX = 44;
  const rightX = 356;
  
  let currentY = 310;
  let detailsHtml = "";

  const addRow = (label: string, value: string, valueColor = '#0F172A') => {
    detailsHtml += `
      <text x="${leftX}" y="${currentY}" class="detail-label">${escapeXml(label)}</text>
      <text x="${rightX}" y="${currentY}" text-anchor="end" class="detail-value" fill="${valueColor}">${escapeXml(value)}</text>
    `;
    currentY += rowHeight;
  };

  addRow(isSender ? "Sent to" : "Received from", partyName);
  addRow("Reference", String(transfer.reference), "#0f766e"); // Teal brand color
  addRow("Payment Status", String(transfer.status), statusColor);
  addRow("Date", formattedDate);
  if (desc) {
    const shortDesc = desc.length > 40 ? desc.substring(0, 37) + '...' : desc;
    addRow("Description", shortDesc);
  }

  // Adjusting heights dynamically based on whether description existed or not
  const totalLineY = currentY + 10;
  const totalRowY = currentY + 45;
  const ticketEnd = totalRowY + 30;
  const canvasHeight = ticketEnd + 100;

  return `<?xml version="1.0" encoding="UTF-8"?>
<svg width="400" height="${canvasHeight}" viewBox="0 0 400 ${canvasHeight}" xmlns="http://www.w3.org/2000/svg">
  <defs>
    <!-- Drop shadow mimicking mobile elevation -->
    <filter id="shadow" x="-5%" y="-5%" width="110%" height="110%">
      <feDropShadow dx="0" dy="8" stdDeviation="12" flood-color="#000000" flood-opacity="0.08"/>
    </filter>
    <style>
      .bg-app { fill: #F8FAFC; }
      .bg-ticket { fill: #ffffff; }
      .status-title { font-family: 'Segoe UI', Arial, sans-serif; font-size: 20px; font-weight: bold; fill: #0f172a; }
      .amount-label { font-family: 'Segoe UI', Arial, sans-serif; font-size: 11px; font-weight: bold; fill: #64748b; letter-spacing: 1px; text-transform: uppercase; }
      .amount-value { font-family: 'Segoe UI', Arial, sans-serif; font-size: 34px; font-weight: 800; }
      .detail-label { font-family: 'Segoe UI', Arial, sans-serif; font-size: 13px; font-weight: 600; fill: #64748b; }
      .detail-value { font-family: 'Segoe UI', Arial, sans-serif; font-size: 14px; font-weight: 600; }
      .total-label { font-family: 'Segoe UI', Arial, sans-serif; font-size: 15px; font-weight: bold; fill: #0f172a; }
      .total-value { font-family: 'Segoe UI', Arial, sans-serif; font-size: 18px; font-weight: 800; fill: #0f172a; }
      .footer-main { font-family: 'Segoe UI', Arial, sans-serif; font-size: 12px; font-weight: 600; fill: #94a3b8; }
      .footer-sub { font-family: 'Segoe UI', Arial, sans-serif; font-size: 11px; fill: #cbd5e1; }
    </style>
  </defs>

  <!-- Background Canvas -->
  <rect width="100%" height="100%" class="bg-app"/>

  <!-- Logo Placement (Centered) -->
  <image href="${LOGO_HREF}" x="170" y="30" width="60" height="60" preserveAspectRatio="xMidYMid meet"/>
  
  <text x="200" y="115" text-anchor="middle" class="status-title">${statusTitle}</text>

  <!-- Ticket Body with Drop Shadow -->
  <rect x="20" y="${startY}" width="360" height="${ticketEnd - startY}" rx="24" class="bg-ticket" filter="url(#shadow)"/>

  <!-- Top Section (Amount) -->
  <text x="200" y="${startY + 35}" text-anchor="middle" class="amount-label">Total Amount</text>
  <text x="200" y="${startY + 80}" text-anchor="middle" class="amount-value" fill="${statusColor}">${transfer.currency} ${formattedAmount}</text>

  <!-- Ticket Perforation Line -->
  <line x1="40" y1="${perforationY}" x2="360" y2="${perforationY}" stroke="#E2E8F0" stroke-width="2" stroke-dasharray="8,6" />
  <!-- Left/Right Punch Holes (Matching background color to look empty) -->
  <circle cx="20" cy="${perforationY}" r="14" class="bg-app" />
  <circle cx="380" cy="${perforationY}" r="14" class="bg-app" />

  <!-- Bottom Section (Details) -->
  ${detailsHtml}

  <!-- Total Separator & Row -->
  <line x1="40" y1="${totalLineY}" x2="360" y2="${totalLineY}" stroke="#F1F5F9" stroke-width="2" />
  <text x="${leftX}" y="${totalRowY}" class="total-label">${isSender ? "Total Paid" : "Total Received"}</text>
  <text x="${rightX}" y="${totalRowY}" text-anchor="end" class="total-value">${transfer.currency} ${formattedAmount}</text>

  <!-- Footer Branding -->
  <text x="200" y="${canvasHeight - 40}" text-anchor="middle" class="footer-main">SuperKilo Money Transfer</text>
  <text x="200" y="${canvasHeight - 20}" text-anchor="middle" class="footer-sub">Generated on ${new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric'})}</text>
</svg>`
}